import{_ as n,o as a,c as o,a2 as e}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"OpenCode — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/opencode/context-management.md","filePath":"research/agents/opencode/context-management.md"}'),l={name:"research/agents/opencode/context-management.md"};function p(t,s,c,r,i,y){return a(),o("div",null,[...s[0]||(s[0]=[e(`<h1 id="opencode-—-context-management" tabindex="-1">OpenCode — Context Management <a class="header-anchor" href="#opencode-—-context-management" aria-label="Permalink to &quot;OpenCode — Context Management&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>OpenCode&#39;s context management centers around three strategies: token usage tracking per session, auto-compaction when approaching the context window limit, and session persistence via SQLite. Unlike some agents that implement sophisticated token counting or sliding window approaches, OpenCode takes a pragmatic approach—letting the LLM providers handle most token management while providing conversation summarization as the primary context reduction mechanism.</p><h2 id="token-usage-tracking" tabindex="-1">Token Usage Tracking <a class="header-anchor" href="#token-usage-tracking" aria-label="Permalink to &quot;Token Usage Tracking&quot;">​</a></h2><p>Token usage is tracked at the session level after each LLM response:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// internal/llm/agent/agent.go</span></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#9399B2;"> (</span><span style="color:#EBA0AC;font-style:italic;">a </span><span style="color:#94E2D5;">*</span><span style="color:#F9E2AF;font-style:italic;">agent</span><span style="color:#9399B2;">)</span><span style="color:#89B4FA;font-style:italic;"> TrackUsage</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">ctx</span><span style="color:#F9E2AF;font-style:italic;"> context</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">Context</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> sessionID</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#F9E2AF;font-style:italic;"> models</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">Model</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> usage</span><span style="color:#F9E2AF;font-style:italic;"> provider</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">TokenUsage</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> error</span><span style="color:#9399B2;"> {</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">    sess</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> _ </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sessions</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Get</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ctx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sessionID</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Calculate cost from token counts and model pricing</span></span>
<span class="line"><span style="color:#CDD6F4;">    cost </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MInCached</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheCreationTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">        model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MOutCached</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheReadTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">        model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MIn</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">InputTokens</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> +</span></span>
<span class="line"><span style="color:#CDD6F4;">        model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CostPer1MOut</span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;">1</span><span style="color:#CBA6F7;">e</span><span style="color:#FAB387;">6</span><span style="color:#94E2D5;">*</span><span style="color:#CBA6F7;">float64</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">OutputTokens</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">    sess</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Cost </span><span style="color:#94E2D5;">+=</span><span style="color:#CDD6F4;"> cost</span></span>
<span class="line"><span style="color:#CDD6F4;">    sess</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CompletionTokens </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">OutputTokens </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheReadTokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    sess</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">PromptTokens </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">InputTokens </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> usage</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">CacheCreationTokens</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">    a</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sessions</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Save</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ctx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sess</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#F38BA8;"> nil</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="tokenusage-structure" tabindex="-1">TokenUsage Structure <a class="header-anchor" href="#tokenusage-structure" aria-label="Permalink to &quot;TokenUsage Structure&quot;">​</a></h3><p>The provider layer reports token usage via:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// internal/llm/provider/provider.go</span></span>
<span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> TokenUsage</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    InputTokens         </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    OutputTokens        </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    CacheCreationTokens </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    CacheReadTokens     </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This tracks four dimensions:</p><ol><li><strong>InputTokens</strong>: Standard input tokens consumed</li><li><strong>OutputTokens</strong>: Tokens generated in the response</li><li><strong>CacheCreationTokens</strong>: Tokens used to create prompt caches (Anthropic)</li><li><strong>CacheReadTokens</strong>: Tokens served from cache (Anthropic)</li></ol><h3 id="session-level-tracking" tabindex="-1">Session-Level Tracking <a class="header-anchor" href="#session-level-tracking" aria-label="Permalink to &quot;Session-Level Tracking&quot;">​</a></h3><p>Each session stores cumulative token usage:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// internal/session/session.go</span></span>
<span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> Session</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    ID               </span><span style="color:#CBA6F7;">string</span></span>
<span class="line"><span style="color:#CDD6F4;">    Title            </span><span style="color:#CBA6F7;">string</span></span>
<span class="line"><span style="color:#CDD6F4;">    MessageCount     </span><span style="color:#CBA6F7;">int64</span></span>
<span class="line"><span style="color:#CDD6F4;">    PromptTokens     </span><span style="color:#CBA6F7;">int64</span><span style="color:#6C7086;font-style:italic;">      // Cumulative input tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    CompletionTokens </span><span style="color:#CBA6F7;">int64</span><span style="color:#6C7086;font-style:italic;">      // Cumulative output tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    Cost             </span><span style="color:#CBA6F7;">float64</span><span style="color:#6C7086;font-style:italic;">    // Cumulative USD cost</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // ...</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="cost-calculation" tabindex="-1">Cost Calculation <a class="header-anchor" href="#cost-calculation" aria-label="Permalink to &quot;Cost Calculation&quot;">​</a></h3><p>Costs are calculated per-turn using the model&#39;s pricing data:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// internal/llm/models/models.go</span></span>
<span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> Model</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    CostPer1MIn         </span><span style="color:#CBA6F7;">float64</span><span style="color:#6C7086;font-style:italic;">  // $/1M input tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    CostPer1MOut        </span><span style="color:#CBA6F7;">float64</span><span style="color:#6C7086;font-style:italic;">  // $/1M output tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    CostPer1MInCached   </span><span style="color:#CBA6F7;">float64</span><span style="color:#6C7086;font-style:italic;">  // $/1M cache creation tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    CostPer1MOutCached  </span><span style="color:#CBA6F7;">float64</span><span style="color:#6C7086;font-style:italic;">  // $/1M cache read tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    ContextWindow       </span><span style="color:#CBA6F7;">int64</span><span style="color:#6C7086;font-style:italic;">    // Max context window size</span></span>
<span class="line"><span style="color:#CDD6F4;">    DefaultMaxTokens    </span><span style="color:#CBA6F7;">int64</span><span style="color:#6C7086;font-style:italic;">    // Default max output tokens</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // ...</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Example pricing from the codebase (Anthropic):</p><ul><li>Claude 3.7 Sonnet: $3/1M input, $15/1M output</li><li>Claude 3.5 Haiku: $0.80/1M input, $4/1M output</li></ul><h2 id="context-window-management" tabindex="-1">Context Window Management <a class="header-anchor" href="#context-window-management" aria-label="Permalink to &quot;Context Window Management&quot;">​</a></h2><h3 id="model-context-windows" tabindex="-1">Model Context Windows <a class="header-anchor" href="#model-context-windows" aria-label="Permalink to &quot;Model Context Windows&quot;">​</a></h3><p>Each model definition includes its context window size:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Example from models/anthropic.go</span></span>
<span class="line"><span style="color:#CDD6F4;">Claude37Sonnet</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    ContextWindow</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;">    200000</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">  // 200K tokens</span></span>
<span class="line"><span style="color:#CDD6F4;">    DefaultMaxTokens</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 16384</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">},</span></span></code></pre></div><h3 id="auto-compact-feature" tabindex="-1">Auto-Compact Feature <a class="header-anchor" href="#auto-compact-feature" aria-label="Permalink to &quot;Auto-Compact Feature&quot;">​</a></h3><p>OpenCode includes an auto-compact feature that triggers summarization when approaching the context limit:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">autoCompact</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> true</span><span style="color:#6C7086;font-style:italic;">  // default is true</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>When enabled:</p><ul><li>Monitors token usage during conversation</li><li>Automatically triggers summarization when usage reaches <strong>95% of the model&#39;s context window</strong></li><li>Creates a summary message in the current session</li><li>Subsequent turns start from the summary rather than the full history</li></ul><h3 id="how-compaction-works" tabindex="-1">How Compaction Works <a class="header-anchor" href="#how-compaction-works" aria-label="Permalink to &quot;How Compaction Works&quot;">​</a></h3><p>The summarization flow (from <code>agent.Summarize()</code>):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. Load all messages from the session</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>2. Append summarization prompt:</span></span>
<span class="line"><span>   &quot;Provide a detailed but concise summary of our conversation above.</span></span>
<span class="line"><span>    Focus on information that would be helpful for continuing...&quot;</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>3. Send entire history + prompt to summarize provider</span></span>
<span class="line"><span>   (non-streaming, synchronous call)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>4. Create summary message in the session (role: assistant)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>5. Set session.SummaryMessageID = summary message ID</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>6. On next processGeneration():</span></span>
<span class="line"><span>   - Find summary message index in history</span></span>
<span class="line"><span>   - Truncate all messages before it</span></span>
<span class="line"><span>   - Re-role summary as &quot;user&quot; message</span></span>
<span class="line"><span>   - Continue from there</span></span></code></pre></div><p>The key implementation in <code>processGeneration()</code>:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">session</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> _ </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sessions</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Get</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ctx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sessionID</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#CDD6F4;"> session</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">SummaryMessageID </span><span style="color:#94E2D5;">!=</span><span style="color:#A6E3A1;"> &quot;&quot;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    summaryMsgIndex </span><span style="color:#94E2D5;">:=</span><span style="color:#94E2D5;"> -</span><span style="color:#FAB387;">1</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> i</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> msg </span><span style="color:#94E2D5;">:=</span><span style="color:#CBA6F7;"> range</span><span style="color:#CDD6F4;"> msgs </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> msg</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">ID </span><span style="color:#94E2D5;">==</span><span style="color:#CDD6F4;"> session</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">SummaryMessageID </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            summaryMsgIndex </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> i</span></span>
<span class="line"><span style="color:#CBA6F7;">            break</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> summaryMsgIndex </span><span style="color:#94E2D5;">!=</span><span style="color:#94E2D5;"> -</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        msgs </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> msgs</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">summaryMsgIndex</span><span style="color:#9399B2;">:]</span></span>
<span class="line"><span style="color:#CDD6F4;">        msgs</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;">0</span><span style="color:#9399B2;">].</span><span style="color:#CDD6F4;">Role </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> message</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">User  </span><span style="color:#6C7086;font-style:italic;">// Re-role as user message</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="summarization-prompt" tabindex="-1">Summarization Prompt <a class="header-anchor" href="#summarization-prompt" aria-label="Permalink to &quot;Summarization Prompt&quot;">​</a></h3><p>The summarizer uses a focused prompt:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// internal/llm/prompt/summarizer.go</span></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#89B4FA;font-style:italic;"> SummarizerPrompt</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">_</span><span style="color:#F9E2AF;font-style:italic;"> models</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">ModelProvider</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#A6E3A1;"> \`You are a helpful AI assistant tasked with summarizing conversations.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">When asked to summarize, provide a detailed but concise summary of the conversation.</span></span>
<span class="line"><span style="color:#A6E3A1;">Focus on information that would be helpful for continuing the conversation, including:</span></span>
<span class="line"><span style="color:#A6E3A1;">- What was done</span></span>
<span class="line"><span style="color:#A6E3A1;">- What is currently being worked on</span></span>
<span class="line"><span style="color:#A6E3A1;">- Which files are being modified</span></span>
<span class="line"><span style="color:#A6E3A1;">- What needs to be done next</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">Your summary should be comprehensive enough to provide context but concise enough</span></span>
<span class="line"><span style="color:#A6E3A1;">to be quickly understood.\`</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The in-session trigger prompt is:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>&quot;Provide a detailed but concise summary of our conversation above. Focus on</span></span>
<span class="line"><span>information that would be helpful for continuing the conversation, including</span></span>
<span class="line"><span>what we did, what we&#39;re doing, which files we&#39;re working on, and what we&#39;re</span></span>
<span class="line"><span>going to do next.&quot;</span></span></code></pre></div><h2 id="session-persistence" tabindex="-1">Session Persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session Persistence&quot;">​</a></h2><h3 id="sqlite-storage" tabindex="-1">SQLite Storage <a class="header-anchor" href="#sqlite-storage" aria-label="Permalink to &quot;SQLite Storage&quot;">​</a></h3><p>All conversations are persisted to SQLite, stored in <code>.opencode/</code> within the project directory:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>.opencode/</span></span>
<span class="line"><span>└── opencode.db          # SQLite database</span></span></code></pre></div><p>The database schema (managed by Goose migrations) includes:</p><p><strong>Sessions table</strong>:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> sessions</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    parent_session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    title </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    message_count </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    prompt_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    completion_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    summary_message_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    cost </span><span style="color:#CBA6F7;">REAL</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">    updated_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span></code></pre></div><p><strong>Messages table</strong>:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> messages</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> REFERENCES</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CDD6F4;">(id) </span><span style="color:#CBA6F7;">ON DELETE CASCADE</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    role</span><span style="color:#CBA6F7;"> TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    parts </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,       </span><span style="color:#6C7086;font-style:italic;">-- JSON-serialized ContentPart array</span></span>
<span class="line"><span style="color:#CDD6F4;">    model </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    finished_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">    updated_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span></code></pre></div><p><strong>Files and file_versions tables</strong> (for undo/redo):</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> files</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    path</span><span style="color:#CBA6F7;"> TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    content </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    -- ...</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> file_versions</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    file_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> REFERENCES</span><span style="color:#CDD6F4;"> files(id),</span></span>
<span class="line"><span style="color:#CDD6F4;">    content </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    -- ...</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span></code></pre></div><h3 id="message-serialization" tabindex="-1">Message Serialization <a class="header-anchor" href="#message-serialization" aria-label="Permalink to &quot;Message Serialization&quot;">​</a></h3><p>Messages use a typed wrapper pattern for serializing heterogeneous content parts to JSON:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> partWrapper</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    Type </span><span style="color:#F9E2AF;font-style:italic;">partType</span><span style="color:#A6E3A1;">    \`json:&quot;type&quot;\`</span></span>
<span class="line"><span style="color:#CDD6F4;">    Data </span><span style="color:#F9E2AF;font-style:italic;">ContentPart</span><span style="color:#A6E3A1;"> \`json:&quot;data&quot;\`</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Content part types:</p><ul><li><code>reasoning</code> — Extended thinking/reasoning content</li><li><code>text</code> — Plain text content</li><li><code>image_url</code> — Image URL reference</li><li><code>binary</code> — Binary data (images, attachments)</li><li><code>tool_call</code> — Tool invocation with parameters</li><li><code>tool_result</code> — Tool execution result</li><li><code>finish</code> — Finish marker with reason and timestamp</li></ul><h3 id="session-types" tabindex="-1">Session Types <a class="header-anchor" href="#session-types" aria-label="Permalink to &quot;Session Types&quot;">​</a></h3><p>OpenCode has several session types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Created By</th><th>Purpose</th></tr></thead><tbody><tr><td>Regular</td><td>User (new chat)</td><td>Main conversation sessions</td></tr><tr><td>Task</td><td>Agent tool</td><td>Sub-agent search sessions</td></tr><tr><td>Title</td><td>Title generator</td><td>Ephemeral title generation sessions</td></tr><tr><td>Summary</td><td>Compact command</td><td>Sessions created from summarization</td></tr></tbody></table><p>Task sessions use <code>parent_session_id</code> to maintain the parent-child relationship, enabling cost rollup from sub-agents to the parent session.</p><h2 id="memory-system-opencode-md" tabindex="-1">Memory System: OpenCode.md <a class="header-anchor" href="#memory-system-opencode-md" aria-label="Permalink to &quot;Memory System: OpenCode.md&quot;">​</a></h2><p>OpenCode supports a project-level memory file called <code>OpenCode.md</code> (or <code>AGENTS.md</code> in newer versions):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># Memory</span></span>
<span class="line"><span>If the current working directory contains a file called OpenCode.md,</span></span>
<span class="line"><span>it will be automatically added to your context. This file serves</span></span>
<span class="line"><span>multiple purposes:</span></span>
<span class="line"><span>1. Storing frequently used bash commands (build, test, lint, etc.)</span></span>
<span class="line"><span>2. Recording the user&#39;s code style preferences</span></span>
<span class="line"><span>3. Maintaining useful information about the codebase structure</span></span></code></pre></div><p>This file is loaded into the system prompt context automatically, providing persistent project-specific instructions across sessions. The <code>/init</code> command analyzes the project and creates this file.</p><h2 id="context-usage-patterns" tabindex="-1">Context Usage Patterns <a class="header-anchor" href="#context-usage-patterns" aria-label="Permalink to &quot;Context Usage Patterns&quot;">​</a></h2><h3 id="what-s-sent-to-the-llm" tabindex="-1">What&#39;s Sent to the LLM <a class="header-anchor" href="#what-s-sent-to-the-llm" aria-label="Permalink to &quot;What&#39;s Sent to the LLM&quot;">​</a></h3><p>On each turn, the agent sends:</p><ol><li><strong>System prompt</strong>: Provider-specific base prompt + environment info + LSP info + OpenCode.md content</li><li><strong>Message history</strong>: All messages since session start (or summary point)</li><li><strong>Tool definitions</strong>: JSON Schema for all available tools</li></ol><h3 id="no-client-side-token-counting" tabindex="-1">No Client-Side Token Counting <a class="header-anchor" href="#no-client-side-token-counting" aria-label="Permalink to &quot;No Client-Side Token Counting&quot;">​</a></h3><p>OpenCode does <strong>not</strong> perform client-side token counting or estimation. It relies on:</p><ol><li>The provider&#39;s reported usage (via <code>TokenUsage</code>) after each response</li><li>The model&#39;s context window metadata for auto-compact thresholds</li><li>Provider-side errors when context is exceeded</li></ol><p>This is simpler than approaches like tiktoken-based counting but means context overflow is only detected after it happens (provider returns an error).</p><h3 id="environment-info-injection" tabindex="-1">Environment Info Injection <a class="header-anchor" href="#environment-info-injection" aria-label="Permalink to &quot;Environment Info Injection&quot;">​</a></h3><p>The system prompt includes dynamic environment information:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#89B4FA;font-style:italic;"> getEnvironmentInfo</span><span style="color:#9399B2;">()</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    cwd </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> config</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">WorkingDirectory</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">    isGit </span><span style="color:#94E2D5;">:=</span><span style="color:#89B4FA;font-style:italic;"> isGitRepo</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">cwd</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    platform </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> runtime</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">GOOS</span></span>
<span class="line"><span style="color:#CDD6F4;">    date </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> time</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Now</span><span style="color:#9399B2;">().</span><span style="color:#89B4FA;font-style:italic;">Format</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;1/2/2006&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    ls </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> tools</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">NewLsTool</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">    r</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> _ </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> ls</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Run</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">context</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Background</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> tools</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">ToolCall</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">Input</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> \`{&quot;path&quot;:&quot;.&quot;}\`</span><span style="color:#9399B2;">})</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> fmt</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Sprintf</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">\`</span></span>
<span class="line"><span style="color:#A6E3A1;">&lt;env&gt;</span></span>
<span class="line"><span style="color:#A6E3A1;">Working directory: %s</span></span>
<span class="line"><span style="color:#A6E3A1;">Is directory a git repo: %s</span></span>
<span class="line"><span style="color:#A6E3A1;">Platform: %s</span></span>
<span class="line"><span style="color:#A6E3A1;">Today&#39;s date: %s</span></span>
<span class="line"><span style="color:#A6E3A1;">&lt;/env&gt;</span></span>
<span class="line"><span style="color:#A6E3A1;">&lt;project&gt;</span></span>
<span class="line"><span style="color:#A6E3A1;">%s</span></span>
<span class="line"><span style="color:#A6E3A1;">&lt;/project&gt;\`</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> cwd</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> boolToYesNo</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">isGit</span><span style="color:#9399B2;">),</span><span style="color:#CDD6F4;"> platform</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> date</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> r</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Content</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This gives the LLM immediate awareness of:</p><ul><li>Current working directory</li><li>Whether it&#39;s a git repo</li><li>Operating system platform</li><li>Today&#39;s date</li><li>Directory listing of the project root</li></ul><h2 id="comparison-with-other-agents" tabindex="-1">Comparison with Other Agents <a class="header-anchor" href="#comparison-with-other-agents" aria-label="Permalink to &quot;Comparison with Other Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>OpenCode</th><th>Claude Code</th><th>Aider</th></tr></thead><tbody><tr><td>Token counting</td><td>Server-reported only</td><td>Client + server</td><td>tiktoken</td></tr><tr><td>Context compaction</td><td>Summarize → re-role</td><td>Compact (summary)</td><td>Map/refine</td></tr><tr><td>Persistence</td><td>SQLite per-project</td><td>JSON files</td><td>Git-based</td></tr><tr><td>Memory file</td><td>OpenCode.md</td><td>CLAUDE.md</td><td>.aider.conf.yml</td></tr><tr><td>Auto-compact trigger</td><td>95% of context window</td><td>Configurable</td><td>Manual</td></tr><tr><td>Message truncation</td><td>After summary only</td><td>Sliding window</td><td>By cost</td></tr></tbody></table>`,77)])])}const D=n(l,[["render",p]]);export{C as __pageData,D as default};
